#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int op,l,r,x,w;
}q[N*3],t[N*3];

void Fz(Node &x,Node &y){
    x.op=y.op;
    x.l=y.l;
    x.r=y.r;
    x.x=y.x;
    x.w=y.w;
}

int n,m,v[N],ans[N][2],lst[N],cnt,c[N];
vector<Node> s[N];

bool cmp(Node x,Node y){
    if(x.l==y.l)
        return x.op<y.op;
    return x.l>y.l;
}

void add(int x,int k){
    for(;x<N;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

void del(int x){
    for(;x<N && c[x];x+=(x&(-x)))
        c[x]=0;
}

void CDQ(int l,int r){ 
    if(l==r)
        return;
    int mid=l+r>>1,p=l-1;
    CDQ(l,mid);
    CDQ(mid+1,r);
    vector<int> vc;
    int i,j;
    for(i=mid+1,j=l;i<=r;i++){
        while(j<=mid && q[j].r<=q[i].r){
        	p++;
            Fz(t[p],q[j]);
            if(q[j].op==0)
            	vc.push_back(q[j].x),add(q[j].x,1);
			j++;
        }
        if(q[i].op)
        	ans[q[i].op][1]+=ask(q[i].x)*q[i].w;
        p++;
        Fz(t[p],q[i]);
    }
    while(j<=mid){
    	p++;
        Fz(t[p],q[j]);
        j++; 
	}
    for(int i=l;i<=r;i++)
        Fz(q[i],t[i]);
    for(int i:vc)
        del(i);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&v[i]);
    for(int i=1;i<=m;i++){
        int l,r,a,b;
        scanf("%d%d%d%d",&l,&r,&a,&b);
        q[++cnt]={i,l,r,b,1};
        q[++cnt]={i,l,r,a-1,-1};
        s[l-1].push_back({i,a,b,0,-1});
        s[r].push_back({i,a,b,0,1});
    }
    for(int i=1;i<=n;i++){
        add(v[i],1);
        for(Node j:s[i])
            ans[j.op][0]+=(ask(j.r)-ask(j.l-1))*j.w;
        if(lst[v[i]])
            q[++cnt]={0,lst[v[i]],i,v[i],1};
        lst[v[i]]=i;
    }
    memset(c,0,sizeof(c));
    sort(q+1,q+cnt+1,cmp);
    CDQ(1,cnt);
    for(int i=1;i<=m;i++)
        printf("%d %d\n",ans[i][0],ans[i][0]-ans[i][1]);
    return 0;
}
